import React, { useState, useEffect } from 'react';
import { Bar, Line, Pie } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import WebSocketService from '../services/WebSocketService';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

const Charts = () => {
  const [vehicleStatusData, setVehicleStatusData] = useState({
    labels: ['Active', 'Idle', 'Maintenance', 'Offline'],
    datasets: [
      {
        label: 'Vehicle Status',
        data: [10, 5, 3, 2], // Sample data
        backgroundColor: ['#3B82F6', '#FBBF24', '#EF4444', '#6B7280'],
        borderColor: ['#1E40AF', '#D97706', '#B91C1C', '#4B5563'],
        borderWidth: 1,
      },
    ],
  });

  const [fuelEfficiencyData, setFuelEfficiencyData] = useState({
    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    datasets: [
      {
        label: 'Fuel Efficiency (mpg)',
        data: [25, 27, 26, 28, 30, 29], // Sample data
        fill: false,
        borderColor: '#3B82F6',
        tension: 0.1,
      },
    ],
  });

  const [alertTypeData, setAlertTypeData] = useState({
    labels: ['Speeding', 'Geofence', 'Maintenance', 'Other'],
    datasets: [
      {
        label: 'Alert Types',
        data: [15, 10, 8, 5], // Sample data
        backgroundColor: ['#EF4444', '#10B981', '#FBBF24', '#8B5CF6'],
        borderColor: ['#B91C1C', '#059669', '#D97706', '#6D28D9'],
        borderWidth: 1,
      },
    ],
  });

  useEffect(() => {
    WebSocketService.connect();
    WebSocketService.subscribe('/topic/vehicles', (message) => {
      const vehicleData = JSON.parse(message.body);
      // Update vehicle status (example logic)
      const newStatusData = {
        ...vehicleStatusData,
        datasets: [
          {
            ...vehicleStatusData.datasets[0],
            data: [
              vehicleData.filter(v => v.status === 'ACTIVE').length,
              vehicleData.filter(v => v.status === 'IDLE').length,
              vehicleData.filter(v => v.status === 'MAINTENANCE').length,
              vehicleData.filter(v => v.status === 'OFFLINE').length,
            ],
          },
        ],
      };
      setVehicleStatusData(newStatusData);
    });

    WebSocketService.subscribe('/topic/alerts', (message) => {
      const alertData = JSON.parse(message.body);
      // Update alert types (example logic)
      const newAlertData = {
        ...alertTypeData,
        datasets: [
          {
            ...alertTypeData.datasets[0],
            data: [
              alertData.filter(a => a.type === 'SPEEDING').length,
              alertData.filter(a => a.type === 'GEOFENCE').length,
              alertData.filter(a => a.type === 'MAINTENANCE').length,
              alertData.filter(a => a.type === 'OTHER').length,
            ],
          },
        ],
      };
      setAlertTypeData(newAlertData);
    });

    return () => {
      WebSocketService.disconnect();
    };
  }, []);

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#1F2937',
        },
      },
      title: {
        display: true,
        color: '#1F2937',
        font: { size: 16 },
      },
    },
    scales: {
      x: {
        ticks: { color: '#1F2937' },
        grid: { display: false },
      },
      y: {
        ticks: { color: '#1F2937' },
        grid: { color: '#E5E7EB' },
      },
    },
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
      <div className="stat-card">
        <h2 className="text-lg font-semibold mb-4">Vehicle Status</h2>
        <div className="h-64">
          <Bar
            data={vehicleStatusData}
            options={{
              ...chartOptions,
              plugins: { ...chartOptions.plugins, title: { ...chartOptions.plugins.title, text: 'Vehicle Status Distribution' } },
            }}
          />
        </div>
      </div>
      <div className="stat-card">
        <h2 className="text-lg font-semibold mb-4">Fuel Efficiency</h2>
        <div className="h-64">
          <Line
            data={fuelEfficiencyData}
            options={{
              ...chartOptions,
              plugins: { ...chartOptions.plugins, title: { ...chartOptions.plugins.title, text: 'Fuel Efficiency Over Time' } },
            }}
          />
        </div>
      </div>
      <div className="stat-card">
        <h2 className="text-lg font-semibold mb-4">Alert Types</h2>
        <div className="h-64">
          <Pie
            data={alertTypeData}
            options={{
              ...chartOptions,
              plugins: { ...chartOptions.plugins, title: { ...chartOptions.plugins.title, text: 'Alert Type Distribution' } },
              scales: {}, // Pie charts don't use scales
            }}
          />
        </div>
      </div>
    </div>
  );
};

export default Charts;
